diffs.diff:
- <!DOCTYPE html>
- <html lang="ar" dir="auto">
- <head>
-   <meta charset="UTF-8" />
-   <meta name="viewport" content="width=device-width, initial-scale=1.0" />
-   <title>Forge — AI Workspace</title>
-   <link rel="preconnect" href="https://fonts.googleapis.com" />
-   <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
-   <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet" />
-   <style>
-     *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
- 
-     :root {
-       --bg-base:       #0d1117;
-       --bg-surface:    #161b22;
-       --bg-elevated:   #1c2128;
-       --bg-overlay:    #21262d;
-       --border:        #30363d;
-       --border-muted:  #21262d;
-       --text-primary:  #e6edf3;
-       --text-secondary:#8b949e;
-       --text-muted:    #6e7681;
-       --blue:          #58a6ff;
-       --blue-dark:     #1f6feb;
-       --blue-bg:       #0c2340;
-       --green:         #3fb950;
-       --green-bg:      #0a3320;
-       --amber:         #d29922;
-       --amber-bg:      #2f230a;
-       --red:           #f85149;
-       --red-bg:        #3d0f0e;
-       --purple:        #bc8cff;
-       --radius-sm:     6px;
-       --radius-md:     10px;
-       --radius-lg:     16px;
-       --radius-xl:     24px;
-       --shadow-sm:     0 1px 3px rgba(0,0,0,.4);
-       --shadow-md:     0 4px 16px rgba(0,0,0,.5);
-       --shadow-lg:     0 8px 32px rgba(0,0,0,.6);
-     }
- 
-     body {
-       font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
-       background: var(--bg-base);
-       color: var(--text-primary);
-       height: 100vh;
-       overflow: hidden;
-       font-size: 14px;
-       line-height: 1.5;
-       -webkit-font-smoothing: antialiased;
-     }
- 
-     /* ── App Shell ── */
-     .app {
-       display: flex;
-       flex-direction: column;
-       height: 100vh;
-       max-width: 1600px;
-       margin: 0 auto;
-       padding: 0 20px 16px;
-       overflow: hidden;
-     }
- 
-     /* ── Topbar ── */
-     .topbar {
-       display: flex;
-       align-items: center;
-       justify-content: space-between;
-       padding: 12px 0;
-       border-bottom: 1px solid var(--border-muted);
-       margin-bottom: 16px;
-       flex: 0 0 auto;
-       gap: 16px;
-     }
- 
-     .topbar-brand {
-       display: flex;
-       align-items: center;
-       gap: 10px;
-       flex: 0 0 auto;
-     }
- 
-     .brand-icon {
-       font-size: 22px;
-       color: var(--blue);
-       line-height: 1;
-     }
- 
-     .brand-name {
-       font-size: 18px;
-       font-weight: 700;
-       color: var(--text-primary);
-       letter-spacing: -0.02em;
-     }
- 
-     .brand-sub {
-       font-size: 12px;
-       color: var(--text-muted);
-       font-weight: 400;
-     }
- 
-     .topbar-desc {
-       flex: 1;
-       font-size: 12px;
-       color: var(--text-secondary);
-       text-align: center;
-       max-width: 600px;
-       margin: 0 auto;
-     }
- 
-     .topbar-status {
-       flex: 0 0 auto;
-     }
- 
-     .status-pill {
-       display: inline-flex;
-       align-items: center;
-       gap: 6px;
-       padding: 4px 12px;
-       border-radius: 999px;
-       font-size: 12px;
-       font-weight: 500;
-       background: var(--bg-elevated);
-       border: 1px solid var(--border);
-       color: var(--text-secondary);
-     }
- 
-     .status-pill::before {
-       content: '';
-       display: inline-block;
-       width: 6px;
-       height: 6px;
-       border-radius: 50%;
-       background: var(--text-muted);
-     }
- 
-     .status-pill.active::before  { background: var(--green); animation: pulse 1.6s infinite; }
-     .status-pill.error::before   { background: var(--red); }
-     .status-pill.waiting::before { background: var(--amber); }
- 
-     @keyframes pulse {
-       0%, 100% { opacity: 1; }
-       50%       { opacity: .4; }
-     }
- 
-     /* ── Main workspace grid ── */
-     .workspace-shell {
-       display: grid;
-       grid-template-columns: minmax(0, 3fr) minmax(320px, 1fr);
-       gap: 20px;
-       align-items: stretch;
-       flex: 1;
-       min-height: 0;
-       overflow: hidden;
-     }
- 
-     /* ── Chat panel ── */
-     .chat-panel {
-       background: var(--bg-surface);
-       border: 1px solid var(--border);
-       border-radius: var(--radius-xl);
-       min-height: 0;
-       overflow: hidden;
-       display: flex;
-       flex-direction: column;
-       box-shadow: var(--shadow-md);
-     }
- 
-     .chat-stream {
-       display: flex;
-       flex-direction: column;
-       gap: 10px;
-       flex: 1;
-       min-height: 0;
-       overflow-y: auto;
-       padding: 20px 36px;
-       scroll-behavior: smooth;
-     }
- 
-     .chat-stream::-webkit-scrollbar { width: 4px; }
-     .chat-stream::-webkit-scrollbar-track { background: transparent; }
-     .chat-stream::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px; }
- 
-     .chat-message {
-       border: 1px solid var(--border-muted);
-       border-radius: var(--radius-lg);
-       padding: 14px 18px;
-       background: var(--bg-elevated);
-       box-shadow: var(--shadow-sm);
-       width: 100%;
-       animation: msgEnter .2s ease-out;
-     }
- 
-     @keyframes msgEnter {
-       from { opacity: 0; transform: translateY(6px); }
-       to   { opacity: 1; transform: translateY(0); }
-     }
- 
-     .chat-message[dir="rtl"] { direction: rtl; text-align: right; }
-     .chat-message[dir="ltr"] { direction: ltr; text-align: left; }
- 
-     .chat-message.user {
-       background: linear-gradient(160deg, var(--blue-bg) 0%, #0a2240 100%);
-       border-color: #1d4e89;
-       align-self: flex-end;
-     }
- 
-     .chat-message.assistant {
-       background: var(--bg-elevated);
-       align-self: flex-start;
-     }
- 
-     .message-label {
-       font-size: 11px;
-       text-transform: uppercase;
-       letter-spacing: .08em;
-       color: var(--text-muted);
-       margin-bottom: 8px;
-       font-weight: 600;
-     }
- 
-     .message-title {
-       margin: 0 0 10px;
-       font-size: 16px;
-       font-weight: 600;
-     }
- 
-     /* ── Composer ── */
-     .composer-message {
-       border-top: 1px solid var(--border-muted);
-       background: var(--bg-base);
-       padding: 10px 16px;
-       display: flex;
-       flex-direction: column;
-       gap: 6px;
-     }
- 
-     .composer-input-row {
-       display: flex;
-       align-items: flex-end;
-       gap: 10px;
-     }
- 
-     .composer-message textarea {
-       min-height: 44px;
-       max-height: 120px;
-       resize: none;
-       border-radius: var(--radius-lg);
-       padding: 11px 14px;
-       font-size: 14px;
-       flex: 1;
-       border: 1px solid var(--border);
-       background: var(--bg-elevated);
-       color: var(--text-primary);
-       font-family: inherit;
-       outline: none;
-       transition: border-color .15s;
-     }
- 
-     .composer-message textarea:focus { border-color: var(--blue); }
- 
-     .send-icon-btn {
-       width: 42px;
-       height: 42px;
-       border-radius: 50%;
-       padding: 0;
-       font-size: 18px;
-       line-height: 1;
-       background: var(--blue);
-       color: #082f49;
-       border: none;
-       cursor: pointer;
-       font-weight: 700;
-       transition: background .15s, transform .1s;
-     }
- 
-     .send-icon-btn:hover { background: #79bcff; transform: scale(1.05); }
-     .send-icon-btn:disabled { opacity: .5; cursor: not-allowed; transform: none; }
- 
-     .status-inline {
-       font-size: 11px;
-       color: var(--text-muted);
-       padding-left: 4px;
-       min-height: 16px;
-     }
- 
-     /* ── Sidebar ── */
-     .workspace-sidebar {
-       display: flex;
-       flex-direction: column;
-       gap: 14px;
-       min-height: 0;
-       overflow-y: auto;
-       padding-right: 2px;
-     }
- 
-     .workspace-sidebar::-webkit-scrollbar { width: 4px; }
-     .workspace-sidebar::-webkit-scrollbar-track { background: transparent; }
-     .workspace-sidebar::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px; }
- 
-     .sidebar-card {
-       background: var(--bg-surface);
-       border: 1px solid var(--border);
-       border-radius: var(--radius-lg);
-       padding: 16px;
-       box-shadow: var(--shadow-sm);
-     }
- 
-     .sidebar-card h2 {
-       margin: 0 0 12px;
-       font-size: 14px;
-       font-weight: 600;
-       color: var(--text-secondary);
-       text-transform: uppercase;
-       letter-spacing: .06em;
-     }
- 
-     .card-header {
-       display: flex;
-       align-items: center;
-       justify-content: space-between;
-       margin-bottom: 12px;
-     }
- 
-     .card-header h2 { margin: 0; }
- 
-     .icon-btn {
-       width: 28px;
-       height: 28px;
-       border-radius: var(--radius-sm);
-       border: 1px solid var(--border);
-       background: var(--bg-elevated);
-       color: var(--text-secondary);
-       font-size: 15px;
-       cursor: pointer;
-       display: flex;
-       align-items: center;
-       justify-content: center;
-       transition: background .15s, color .15s;
-     }
- 
-     .icon-btn:hover { background: var(--bg-overlay); color: var(--text-primary); }
- 
-     /* ── Form controls ── */
-     label {
-       display: block;
-       margin-bottom: 6px;
-       font-size: 12px;
-       color: var(--text-secondary);
-       font-weight: 500;
-     }
- 
-     select {
-       width: 100%;
-       border-radius: var(--radius-md);
-       border: 1px solid var(--border);
-       background: var(--bg-elevated);
-       color: var(--text-primary);
-       padding: 8px 10px;
-       font-size: 13px;
-       font-family: inherit;
-       outline: none;
-       cursor: pointer;
-     }
- 
-     select:focus { border-color: var(--blue); }
- 
-     textarea {
-       width: 100%;
-       border-radius: var(--radius-md);
-       border: 1px solid var(--border);
-       background: var(--bg-elevated);
-       color: var(--text-primary);
-       padding: 8px 10px;
-       font-size: 13px;
-       font-family: inherit;
-       outline: none;
-       resize: vertical;
-     }
- 
-     textarea:focus { border-color: var(--blue); }
- 
-     /* ── Buttons ── */
-     button {
-       border: none;
-       border-radius: var(--radius-md);
-       padding: 8px 14px;
-       font-size: 13px;
-       font-weight: 600;
-       cursor: pointer;
-       font-family: inherit;
-       transition: opacity .15s, background .15s;
-     }
- 
-     button:disabled { opacity: .45; cursor: not-allowed; }
- 
-     .primary  { background: var(--blue); color: #082f49; }
-     .primary:hover:not(:disabled)  { background: #79bcff; }
- 
-     .secondary {
-       background: var(--bg-elevated);
-       color: var(--text-primary);
-       border: 1px solid var(--border);
-     }
-     .secondary:hover:not(:disabled) { background: var(--bg-overlay); }
- 
-     .danger {
-       background: var(--red-bg);
-       color: #fca5a5;
-       border: 1px solid #7f1d1d;
-     }
-     .danger:hover:not(:disabled) { background: #4d1212; }
- 
-     /* ── Output / info boxes ── */
-     .output-box {
-       background: var(--bg-elevated);
-       border: 1px solid var(--border-muted);
-       border-radius: var(--radius-md);
-       padding: 10px 12px;
-       white-space: pre-wrap;
-       overflow: auto;
-       line-height: 1.6;
-       font-size: 12px;
-       color: var(--text-secondary);
-     }
- 
-     .output-box.empty { color: var(--text-muted); }
- 
-     .compact-box { min-height: 72px; }
- 
-     .status {
-       padding: 10px 12px;
-       border-radius: var(--radius-md);
-       background: var(--bg-elevated);
-       border: 1px solid var(--border-muted);
-       color: var(--text-secondary);
-       min-height: 40px;
-       white-space: pre-wrap;
-       font-size: 12px;
-     }
- 
-     /* ── File / history cards ── */
-     .file-list {
-       display: flex;
-       flex-direction: column;
-       gap: 8px;
-     }
- 
-     .file-card {
-       background: var(--bg-elevated);
-       border: 1px solid var(--border-muted);
-       border-radius: var(--radius-md);
-       padding: 10px 12px;
-       font-size: 12px;
-     }
- 
-     .file-card.empty { color: var(--text-muted); }
- 
-     .file-path {
-       font-weight: 600;
-       margin-bottom: 6px;
-       color: var(--blue);
-       word-break: break-word;
-       font-size: 12px;
-     }
- 
-     .file-preview {
-       color: var(--text-secondary);
-       white-space: pre-wrap;
-       word-break: break-word;
-       line-height: 1.6;
-     }
- 
-     /* ── Actions row ── */
-     .actions {
-       display: flex;
-       gap: 8px;
-       margin-top: 12px;
-       flex-wrap: wrap;
-     }
- 
-     .approval-actions { margin-top: 10px; }
- 
-     .assistant-stack {
-       display: flex;
-       flex-direction: column;
-       gap: 8px;
-     }
- 
-     /* ── Auth fields ── */
-     .auth-fields {
-       display: flex;
-       flex-direction: column;
-       gap: 8px;
-     }
- 
-     .auth-fields textarea { min-height: 38px; }
- 
-     /* ── Strategy choice ── */
-     .strategy-choice-list {
-       display: flex;
-       flex-direction: column;
-       gap: 8px;
-     }
- 
-     .strategy-choice-btn {
-       width: 100%;
-       text-align: left;
-       background: var(--bg-elevated);
-       color: var(--text-primary);
-       border: 1px solid var(--border);
-       border-radius: var(--radius-md);
-       padding: 10px 12px;
-       cursor: pointer;
-       font-size: 13px;
-       line-height: 1.5;
-       transition: border-color .15s, background .15s;
-     }
- 
-     .strategy-choice-btn:hover { border-color: var(--blue); background: var(--bg-overlay); }
-     .strategy-choice-btn strong { display: block; color: var(--blue); margin-bottom: 4px; }
- 
-     /* ── Pending confirmation message style ── */
-     .chat-message.assistant.mode-pending-confirmation {
-       border-color: var(--blue);
-       border-left-width: 3px;
-     }
-     .chat-message.assistant.mode-pending-confirmation .message-title {
-       color: var(--blue);
-     }
- 
-     /* ── Quick-reply chips ── */
-     .quick-reply-chips {
-       display: flex;
-       flex-wrap: wrap;
-       gap: 8px;
-       margin-top: 10px;
-     }
- 
-     .quick-reply-chip {
-       background: var(--bg-elevated);
-       color: var(--blue);
-       border: 1px solid var(--blue);
-       border-radius: 16px;
-       padding: 5px 14px;
-       font-size: 13px;
-       cursor: pointer;
-       transition: background .15s, color .15s;
-       white-space: nowrap;
-     }
- 
-     .quick-reply-chip:hover {
-       background: var(--blue);
-       color: #fff;
-     }
- 
-     .quick-reply-chip.selected {
-       background: var(--blue);
-       color: #fff;
-       font-weight: 600;
-     }
- 
-     .quick-reply-send {
-       display: inline-flex;
-       align-items: center;
-       margin-top: 4px;
-       padding: 5px 14px;
-       background: var(--blue-dark);
-       color: #fff;
-       border: none;
-       border-radius: var(--radius-sm);
-       cursor: pointer;
-       font-size: 13px;
-       font-family: inherit;
-       transition: background .15s;
-     }
- 
-     .quick-reply-send:hover { background: var(--blue); }
- 
-     /* ── Streaming cursor ── */
-     .stream-cursor {
-       display: inline-block;
-       width: 2px;
-       height: 1em;
-       background: var(--text-primary);
-       margin-left: 2px;
-       vertical-align: text-bottom;
-       animation: blink .7s step-end infinite;
-     }
- 
-     @keyframes blink { 50% { opacity: 0; } }
- 
-     /* ── Governance badges ── */
-     .gov-badges {
-       display: flex;
-       flex-direction: column;
-       gap: 6px;
-     }
- 
-     .gov-badge-row {
-       display: flex;
-       align-items: center;
-       justify-content: space-between;
-       padding: 4px 0;
-       border-bottom: 1px solid var(--border-muted);
-     }
- 
-     .gov-badge-row:last-child { border-bottom: none; }
- 
-     .badge-label {
-       font-size: 12px;
-       color: var(--text-secondary);
-     }
- 
-     .badge {
-       display: inline-block;
-       padding: 2px 8px;
-       border-radius: 999px;
-       font-size: 11px;
-       font-weight: 600;
-       letter-spacing: .02em;
-     }
- 
-     .badge-unknown  { background: var(--bg-overlay); color: var(--text-muted); border: 1px solid var(--border); }
-     .badge-pass     { background: var(--green-bg); color: var(--green); border: 1px solid #145523; }
-     .badge-fail     { background: var(--red-bg); color: var(--red); border: 1px solid #5c1a19; }
-     .badge-warn     { background: var(--amber-bg); color: var(--amber); border: 1px solid #5a3d08; }
-     .badge-loading  { background: var(--blue-bg); color: var(--blue); border: 1px solid #1a3f6e; }
- 
-     /* ── Project context header ── */
-     .project-row {
-       display: flex;
-       align-items: center;
-       justify-content: space-between;
-       gap: 10px;
-       margin-bottom: 10px;
-     }
- 
-     .project-row label { margin-bottom: 0; }
- 
-     /* ── Footer ── */
-     .footer {
-       margin-top: 10px;
-       padding-top: 8px;
-       border-top: 1px solid var(--border-muted);
-       color: var(--text-muted);
-       font-size: 11px;
-       text-align: center;
-       flex: 0 0 auto;
-     }
- 
-     /* ── Hidden state (legacy boxes kept for JS) ── */
-     .hidden-state { display: none; }
- 
-     /* ── Responsive ── */
-     @media (max-width: 900px) {
-       .workspace-shell { grid-template-columns: 1fr; }
-       .topbar-desc { display: none; }
-     }
-   </style>
- </head>
- <body>
-   <div class="app">
- 
-     <!-- Topbar -->
-     <header class="topbar">
-       <div class="topbar-brand">
-         <span class="brand-icon">⬡</span>
-         <span class="brand-name">Forge</span>
-         <span class="brand-sub">AI Workspace</span>
-       </div>
-       <p class="topbar-desc">اكتب طلبك بالعربي أو بالإنجليزي — النظام يجهز Draft منظم بعد موافقتك قبل أي تنفيذ.</p>
-       <div class="topbar-status">
-         <div id="globalStatusPill" class="status-pill">Ready</div>
-       </div>
-     </header>
- 
-     <!-- Workspace -->
-     <div class="workspace-shell">
- 
-       <!-- Chat panel -->
-       <div class="chat-panel">
-         <div class="chat-stream">
- 
-           <!-- Legacy output boxes (hidden, kept for JS) -->
-           <div class="hidden-state" aria-hidden="true">
-             <div id="responseBox"  class="output-box empty">No response yet.</div>
-             <div id="filesBox"     class="file-list"><div class="file-card empty">No files proposed yet.</div></div>
-             <div id="previewBox"   class="file-list"><div class="file-card empty">No diff preview yet.</div></div>
-             <div id="analysisBox"  class="output-box empty">No operation analysis yet.</div>
-           </div>
- 
-         </div>
- 
-         <!-- Composer -->
-         <div class="composer-message">
-           <div class="composer-input-row">
-             <textarea id="requestInput" placeholder="اكتب رسالتك هنا..."></textarea>
-             <button id="chatSendBtn" class="send-icon-btn" title="Send">➜</button>
-           </div>
-           <div id="statusBox" class="status-inline">Ready.</div>
-         </div>
-       </div>
- 
-       <!-- Sidebar -->
-       <div class="workspace-sidebar">
- 
-         <!-- Project Context -->
-         <div class="sidebar-card">
-           <h2>Project Context</h2>
-           <div class="project-row">
-             <label for="projectSelect">Active project</label>
-             <div style="display:flex;gap:6px;">
-               <button id="newProjectBtn" type="button" class="secondary">+ New</button>
-               <button id="deleteProjectBtn" type="button" class="secondary" title="حذف المشروع الحالي نهائياً" style="color:var(--red);border-color:var(--red);">🗑</button>
-             </div>
-           </div>
-           <select id="projectSelect"></select>
-           <div id="projectStateBox" class="status" style="margin-top:10px;">Loading project state...</div>
-         </div>
- 
-         <!-- Decision Control -->
-         <div class="sidebar-card">
-           <h2>Decision Control</h2>
-           <label for="approverRoleSelect">Approver role</label>
-           <select id="approverRoleSelect">
-             <option value="cto">cto</option>
-           </select>
