-     async function streamChatMessage(message, projectId) {
-       // Bug-4 fix: never display or send an empty / placeholder message
-       if (!message || !message.trim()) return;
-       const lang = detectUserLanguage(message);
-       pushMessage("user", "", `<div class="file-preview">${formatMessageText(message)}</div>`);
-       requestInput.value = "";
-       chatSendBtn.disabled = true;
-       setStatus(lang === "ar" ? "يكتب..." : "Typing...");
- 
-       const wrapper = document.createElement("div");
-       wrapper.className = "chat-message assistant";
-       wrapper.setAttribute("dir", lang === "ar" ? "rtl" : "ltr");
-       const label = document.createElement("div");
-       label.className = "message-label";
-       label.textContent = "AI Workspace";
-       const title = document.createElement("h2");
-       title.className = "message-title";
-       title.textContent = lang === "ar" ? "رد" : "Response";
-       const contentEl = document.createElement("div");
-       contentEl.className = "file-preview";
-       const cursor = document.createElement("span");
-       cursor.className = "stream-cursor";
-       contentEl.appendChild(cursor);
-       wrapper.appendChild(label);
-       wrapper.appendChild(title);
-       wrapper.appendChild(contentEl);
-       chatStream.appendChild(wrapper);
-       chatStream.scrollTop = chatStream.scrollHeight;
- 
-       let fullText = "";
-       try {
-         const apiBase = window.__FORGE_API_BASE__ || window.location.origin.replace(":3000", ":3100");
-         const res = await fetch(`${apiBase}/api/ai-os/chat/stream`, {
-           method: "POST",
-           headers: { "Content-Type": "application/json" },
-           body: JSON.stringify({ message, project_id: projectId, user_language: lang })
-         });
- 
-         const reader = res.body.getReader();
-         const decoder = new TextDecoder();
-         let buf = "";
- 
-         while (true) {
-           const { done, value } = await reader.read();
-           if (done) break;
-           buf += decoder.decode(value, { stream: true });
-           const parts = buf.split("\n\n");
-           buf = parts.pop();
-           for (const part of parts) {
-             if (!part.startsWith("data: ")) continue;
-             let evt;
-             try { evt = JSON.parse(part.slice(6)); } catch { continue; }
-             if (evt.type === "chunk") {
-               fullText += evt.c;
-               contentEl.textContent = fullText;
-               contentEl.appendChild(cursor);
-               chatStream.scrollTop = chatStream.scrollHeight;
-             } else if (evt.type === "done") {
-               fullText = evt.message || fullText;
-               contentEl.textContent = fullText;
-               cursor.remove();
-               if (evt.mode === "PENDING_CONFIRMATION") {
-                 title.textContent = lang === "ar" ? "تأكيد مطلوب" : "Confirmation needed";
-                 wrapper.classList.add("mode-pending-confirmation");
-               }
-               if (Array.isArray(evt.suggested_answers) && evt.suggested_answers.length > 0) {
-                 renderQuickReplies(evt.suggested_answers);
-               }
-               chatStream.scrollTop = chatStream.scrollHeight;
-             } else if (evt.type === "error") {
-               contentEl.textContent = lang === "ar" ? "حدث خطأ. حاول مجدداً." : "An error occurred. Please try again.";
-               cursor.remove();
-             }
-           }
-         }
-       } catch (err) {
-         contentEl.textContent = lang === "ar" ? "تعذّر الاتصال بالخادم." : "Could not reach server.";
-         cursor.remove();
-       }
- 
-       setStatus("");
-       chatSendBtn.disabled = false;
-     }
